let name = 'PyMaster';       // like: name = 'PyMaster'
const PI = 3.14159;          // like: PI = 3.14159 (but truly constant)
let scores = [95, 87, 92];   // like: scores = [95, 87, 92]

// Objects — like Python dicts but keys don't need quotes
const student = {
    name: 'Alice',
    age: 22,
    grades: [90, 85, 95],
    isActive: true
};

// Functions — regular and arrow
function greet(name) {
    return `Hello, ${name}!`;     // Template literal = f-string
}

// Array methods — like Python list comprehensions
const numbers = [1, 2, 3, 4, 5];
const doubled = numbers.map(n => n * 2);        // [2, 4, 6, 8, 10]
const evens = numbers.filter(n => n % 2 === 0); // [2, 4]
const sum = numbers.reduce((acc, n) => acc + n, 0); // 15

// DOM Manipulation — interacting with HTML
const heading = document.querySelector('h1');
heading.textContent = 'Welcome to PyMasters!';

const button = document.querySelector('#submit-btn');
button.addEventListener('click', () => {
    console.log('Button clicked!');
});

// Fetch API — making HTTP requests from the browser
async function getUsers() {
    const response = await fetch('https://api.example.com/users');
    const data = await response.json();
    console.log(data);
}

// POST request with fetch
async function createUser(userData) {
    const response = await fetch('https://api.example.com/users', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(userData)
    });
    return await response.json();
}

